import{_ as t,o as l,c as e,ag as i}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"我的投资理财心得","description":"记录我的A股投资实践，包括选股思路、仓位管理、风险控制等心得体会，以及踩过的一些坑。","frontmatter":{"title":"我的投资理财心得","date":"2023-12-20T00:00:00.000Z","tags":["投资","理财","A股","心得"],"description":"记录我的A股投资实践，包括选股思路、仓位管理、风险控制等心得体会，以及踩过的一些坑。"},"headers":[],"relativePath":"posts/investment-experience.md","filePath":"posts/investment-experience.md"}'),n={name:"posts/investment-experience.md"};function r(s,a,o,h,d,c){return l(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="我的投资理财心得" tabindex="-1">我的投资理财心得 <a class="header-anchor" href="#我的投资理财心得" aria-label="Permalink to &quot;我的投资理财心得&quot;">​</a></h1><p>作为一个普通的上班族，我也是从2020年开始接触A股投资。几年下来，有赚有亏，积累了一些经验和教训，记录下来供参考。</p><h2 id="🎯-我的投资理念" tabindex="-1">🎯 我的投资理念 <a class="header-anchor" href="#🎯-我的投资理念" aria-label="Permalink to &quot;🎯 我的投资理念&quot;">​</a></h2><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><ol><li><strong>闲钱投资</strong>：只用3-5年不用的钱</li><li><strong>不杠杆</strong>：拒绝借钱炒股</li><li><strong>分散持仓</strong>：不把鸡蛋放一个篮子</li><li><strong>长期持有</strong>：好公司值得等待</li></ol><h3 id="风险认知" tabindex="-1">风险认知 <a class="header-anchor" href="#风险认知" aria-label="Permalink to &quot;风险认知&quot;">​</a></h3><blockquote><p>股市有风险，投资需谨慎。这不是空话，是真金白银换来的教训。</p></blockquote><p>我的风险承受能力：</p><ul><li>最大亏损：不影响生活</li><li>止损线：-15%</li><li>盈利预期：年化8-15%</li></ul><h2 id="📊-我的持仓策略" tabindex="-1">📊 我的持仓策略 <a class="header-anchor" href="#📊-我的持仓策略" aria-label="Permalink to &quot;📊 我的持仓策略&quot;">​</a></h2><h3 id="仓位分配" tabindex="-1">仓位分配 <a class="header-anchor" href="#仓位分配" aria-label="Permalink to &quot;仓位分配&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│      防守仓位 (40%)             │</span></span>
<span class="line"><span>│   银行ETF、高股息股票           │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│      平衡仓位 (35%)             │</span></span>
<span class="line"><span>│   指数基金、优质成长股          │</span></span>
<span class="line"><span>├─────────────────────────────────┤</span></span>
<span class="line"><span>│      进攻仓位 (25%)             │</span></span>
<span class="line"><span>│   AI、新能源等热门板块          │</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span></code></pre></div><h3 id="选股标准" tabindex="-1">选股标准 <a class="header-anchor" href="#选股标准" aria-label="Permalink to &quot;选股标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>要求</th><th>说明</th></tr></thead><tbody><tr><td>行业</td><td>熟悉领域</td><td>优先自己了解的</td></tr><tr><td>估值</td><td>PE &lt; 行业平均</td><td>不要买太贵的</td></tr><tr><td>分红</td><td>稳定分红</td><td>高股息更安全</td></tr><tr><td>流动性</td><td>日均成交 &gt; 1亿</td><td>方便进出</td></tr></tbody></table><h2 id="🛡️-风险控制" tabindex="-1">🛡️ 风险控制 <a class="header-anchor" href="#🛡️-风险控制" aria-label="Permalink to &quot;🛡️ 风险控制&quot;">​</a></h2><h3 id="止损策略" tabindex="-1">止损策略 <a class="header-anchor" href="#止损策略" aria-label="Permalink to &quot;止损策略&quot;">​</a></h3><ul><li>个股亏损 &gt; 10%：反思逻辑</li><li>个股亏损 &gt; 15%：止损离场</li><li>整体账户回撤 &gt; 20%：减仓观望</li></ul><h3 id="分散原则" tabindex="-1">分散原则 <a class="header-anchor" href="#分散原则" aria-label="Permalink to &quot;分散原则&quot;">​</a></h3><ul><li>单只股票不超过总仓位20%</li><li>单个行业不超过总仓位30%</li><li>持仓不少于5只股票</li></ul><h3 id="心态管理" tabindex="-1">心态管理 <a class="header-anchor" href="#心态管理" aria-label="Permalink to &quot;心态管理&quot;">​</a></h3><ol><li><strong>不追涨杀跌</strong>：别人恐惧时我贪婪</li><li><strong>不频繁交易</strong>：手续费是隐形成本</li><li><strong>不盲目跟风</strong>：要有自己的判断</li></ol><h2 id="📈-操作记录" tabindex="-1">📈 操作记录 <a class="header-anchor" href="#📈-操作记录" aria-label="Permalink to &quot;📈 操作记录&quot;">​</a></h2><h3 id="_2023年总结" tabindex="-1">2023年总结 <a class="header-anchor" href="#_2023年总结" aria-label="Permalink to &quot;2023年总结&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>结果</th><th>教训</th></tr></thead><tbody><tr><td>追涨AI概念股</td><td>小赚</td><td>不应追热点</td></tr><tr><td>持有低估银行股</td><td>稳定收益</td><td>价值投资有效</td></tr><tr><td>重仓一只小盘股</td><td>踩雷</td><td>流动性很重要</td></tr></tbody></table><h3 id="盈利来源" tabindex="-1">盈利来源 <a class="header-anchor" href="#盈利来源" aria-label="Permalink to &quot;盈利来源&quot;">​</a></h3><ul><li>分红收益：约4%</li><li>价差收益：约5%</li><li>打新收益：约2%</li></ul><h2 id="📚-学习资源" tabindex="-1">📚 学习资源 <a class="header-anchor" href="#📚-学习资源" aria-label="Permalink to &quot;📚 学习资源&quot;">​</a></h2><h3 id="书籍推荐" tabindex="-1">书籍推荐 <a class="header-anchor" href="#书籍推荐" aria-label="Permalink to &quot;书籍推荐&quot;">​</a></h3><ol><li>《聪明的投资者》- 价值投资经典</li><li>《穷爸爸富爸爸》- 理财思维入门</li><li>《手把手教你读财报》- 财务分析</li></ol><h3 id="工具推荐" tabindex="-1">工具推荐 <a class="header-anchor" href="#工具推荐" aria-label="Permalink to &quot;工具推荐&quot;">​</a></h3><ul><li><strong>且慢</strong>：基金组合跟踪</li><li><strong>理杏仁</strong>：财报分析</li><li><strong>东方财富</strong>：行情资讯</li></ul><h2 id="⚠️-踩过的坑" tabindex="-1">⚠️ 踩过的坑 <a class="header-anchor" href="#⚠️-踩过的坑" aria-label="Permalink to &quot;⚠️ 踩过的坑&quot;">​</a></h2><h3 id="坑1-听消息炒股" tabindex="-1">坑1：听消息炒股 <a class="header-anchor" href="#坑1-听消息炒股" aria-label="Permalink to &quot;坑1：听消息炒股&quot;">​</a></h3><ul><li>教训：内幕消息不可靠</li><li>建议：独立思考，理性分析</li></ul><h3 id="坑2-all-in-单只股票" tabindex="-1">坑2：All in 单只股票 <a class="header-anchor" href="#坑2-all-in-单只股票" aria-label="Permalink to &quot;坑2：All in 单只股票&quot;">​</a></h3><ul><li>教训：黑天鹅防不胜防</li><li>建议：分散持仓，控制仓位</li></ul><h3 id="坑3-不止损死扛" tabindex="-1">坑3：不止损死扛 <a class="header-anchor" href="#坑3-不止损死扛" aria-label="Permalink to &quot;坑3：不止损死扛&quot;">​</a></h3><ul><li>教训：及时止损是保命技能</li><li>建议：设好止损线严格执行</li></ul><h2 id="💡-2024年展望" tabindex="-1">💡 2024年展望 <a class="header-anchor" href="#💡-2024年展望" aria-label="Permalink to &quot;💡 2024年展望&quot;">​</a></h2><h3 id="关注方向" tabindex="-1">关注方向 <a class="header-anchor" href="#关注方向" aria-label="Permalink to &quot;关注方向&quot;">​</a></h3><ul><li>AI应用层公司</li><li>政策支持的国产替代</li><li>高股息防御板块</li></ul><h3 id="操作计划" tabindex="-1">操作计划 <a class="header-anchor" href="#操作计划" aria-label="Permalink to &quot;操作计划&quot;">​</a></h3><ul><li>保持仓位控制</li><li>减少短线操作</li><li>增加指数基金配置</li></ul><h2 id="✨-投资感悟" tabindex="-1">✨ 投资感悟 <a class="header-anchor" href="#✨-投资感悟" aria-label="Permalink to &quot;✨ 投资感悟&quot;">​</a></h2><blockquote><p>投资是一场修行，修的是心态，炼的是认知。</p></blockquote><ul><li>不要想着暴富，稳健增值才是王道</li><li>亏损不可怕，可怕的是不知道为什么亏损</li><li>持续学习，不断完善自己的投资体系</li></ul><hr><p><em>⚠️ 本文仅为个人记录，不构成投资建议。股市有风险，投资需谨慎。</em></p><p><em>相关阅读</em>：</p><ul><li><a href="/posts/tech-tools-recommendation.html">技术工具推荐清单</a></li></ul>`,50)])])}const b=t(n,[["render",r]]);export{p as __pageData,b as default};
